// PRAGMATIS: Selesaikan masalahnya saja dulu
function updateProfile(userId: string, data: any) {
  const user = db.find(userId);
  if (!user) return;
  // Langsung, mudah dibaca, dan mudah dihapus nanti jika perlu
  db.update(userId, { ...user, ...data });
}
